code = """import json

# Load stock info
with open(locals()['var_function-call-2084531363548133324'], 'r') as f:
    stock_info = json.load(f)

# Create a mapping from Symbol to Company Description
symbol_to_name = {row['Symbol']: row['Company Description'] for row in stock_info}

# Load batch results
with open(locals()['var_function-call-17205639438499487392'], 'r') as f:
    batch1 = json.load(f)
with open(locals()['var_function-call-4670461265691749897'], 'r') as f:
    batch2 = json.load(f)
with open(locals()['var_function-call-7732557377796593632'], 'r') as f:
    batch3 = json.load(f)

# Combine
all_results = batch1 + batch2 + batch3

# Convert Days to int
for row in all_results:
    row['Days'] = int(row['Days'])

# Sort
sorted_results = sorted(all_results, key=lambda x: x['Days'], reverse=True)

# Top 5
top5 = sorted_results[:5]

# Get Company Names
final_list = []
for row in top5:
    desc = symbol_to_name.get(row['Symbol'], "Unknown Company")
    final_list.append({"Symbol": row['Symbol'], "Days": row['Days'], "Company": desc})

print("__RESULT__:")
print(json.dumps(final_list))"""

